import com.zaxxer.hikari.HikariDataSource;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.hibernate.cfg.Configuration;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import javax.sql.DataSource;

@Slf4j
@Configuration
@RequiredArgsConstructor
public class HibernateConfig {

    private final DataSourceProperties dataSourceProperties;
    private final JpaProperties jpaProperties;

    /**
     * Configures Hibernate with properties from application.yml
     */
    @Bean
    public Configuration hibernateConfiguration() {
        log.info("Initializing Hibernate Configuration...");

        Configuration configuration = new Configuration();
        configuration.setProperty("hibernate.connection.url", dataSourceProperties.getUrl());
        configuration.setProperty("hibernate.connection.driver_class", dataSourceProperties.getDriverClassName());
        configuration.setProperty("hibernate.connection.username", dataSourceProperties.getUsername());
        configuration.setProperty("hibernate.connection.password", dataSourceProperties.getPassword());
        configuration.setProperty("hibernate.dialect", jpaProperties.getDialect());
        configuration.setProperty("hibernate.show_sql", String.valueOf(jpaProperties.isShowSql()));
        configuration.setProperty("hibernate.format_sql", String.valueOf(jpaProperties.isFormatSql()));
        configuration.setProperty("hibernate.jdbc.batch_size", String.valueOf(jpaProperties.getJdbcBatchSize()));
        configuration.setProperty("hibernate.id.new_generator_mappings", String.valueOf(jpaProperties.isNewGeneratorMappings()));

        log.info("Hibernate Configuration initialized successfully.");
        return configuration;
    }

    /**
     * Configures a DataSource bean using HikariCP.
     */
    @Bean
    public DataSource dataSource() {
        log.info("Configuring DataSource...");
        HikariDataSource dataSource = new HikariDataSource();
        dataSource.setJdbcUrl(dataSourceProperties.getUrl());
        dataSource.setDriverClassName(dataSourceProperties.getDriverClassName());
        dataSource.setUsername(dataSourceProperties.getUsername());
        dataSource.setPassword(dataSourceProperties.getPassword());
        log.info("DataSource configured successfully.");
        return dataSource;
    }
}

import lombok.Getter;
import lombok.Setter;
import org.springframework.boot.context.properties.ConfigurationProperties;
import org.springframework.stereotype.Component;

@Getter
@Setter
@Component
@ConfigurationProperties(prefix = "spring.jpa.properties.hibernate")
public class JpaProperties {
    private String dialect;
    private boolean showSql;
    private boolean formatSql;
    private int jdbcBatchSize;
    private boolean newGeneratorMappings;
}

import lombok.Getter;
import lombok.Setter;
import org.springframework.boot.context.properties.ConfigurationProperties;
import org.springframework.stereotype.Component;

@Getter
@Setter
@Component
@ConfigurationProperties(prefix = "spring.datasource")
public class DataSourceProperties {
    private String url;
    private String driverClassName;
    private String username;
    private String password;
}
